import React, { useState } from 'react';
import { Target, Plus, ChevronRight, TrendingUp } from 'lucide-react';
import CreateGoalScreen from './CreateGoalScreen';
import GoalDetailsScreen from './GoalDetailsScreen';
import AddGoalFundScreen from './AddGoalFundScreen';
import WithdrawGoalScreen from './WithdrawGoalScreen';

export default function GoalsScreen() {
  const [goals, setGoals] = useState([
    { id: 1, title: 'Dream House', target: 50000, current: 12500, color: 'bg-emerald-500' },
    { id: 2, title: 'New Car', target: 15000, current: 8000, color: 'bg-blue-500' },
    { id: 3, title: 'Vacation', target: 3000, current: 2100, color: 'bg-orange-400' },
  ]);

  const [activeScreen, setActiveScreen] = useState('goals'); // 'goals', 'create', 'details', 'addFunds', 'withdraw'
  const [selectedGoal, setSelectedGoal] = useState(null);

  // Handlers
  const handleCreateGoal = (goal) => {
    setGoals([...goals, { id: Date.now(), ...goal, current: 0 }]);
    setActiveScreen('goals');
  };

  const handleAddFunds = (amount) => {
    setGoals(goals.map(g => g.id === selectedGoal.id ? { ...g, current: g.current + amount } : g));
    setActiveScreen('details');
  };

  const handleWithdraw = (amount) => {
    setGoals(goals.map(g => g.id === selectedGoal.id ? { ...g, current: g.current - amount } : g));
    setActiveScreen('details');
  };

  // Total savings
  const totalSavings = goals.reduce((acc, g) => acc + g.current, 0);

  // Screen rendering
  if (activeScreen === 'create') {
    return <CreateGoalScreen onBack={() => setActiveScreen('goals')} onSave={handleCreateGoal} />;
  }

  if (activeScreen === 'details' && selectedGoal) {
    return (
      <GoalDetailsScreen 
        goal={selectedGoal} 
        onBack={() => setActiveScreen('goals')} 
        onAddFunds={() => setActiveScreen('addFunds')} 
        onWithdraw={() => setActiveScreen('withdraw')} 
      />
    );
  }

  if (activeScreen === 'addFunds' && selectedGoal) {
    return <AddGoalFundScreen goal={selectedGoal} onBack={() => setActiveScreen('details')} onConfirm={handleAddFunds} />;
  }

  if (activeScreen === 'withdraw' && selectedGoal) {
    return <WithdrawGoalScreen goal={selectedGoal} onBack={() => setActiveScreen('details')} onConfirm={handleWithdraw} />;
  }

  // Main Goals Screen
  return (
    <div className="p-5 animate-in fade-in duration-300 bg-white h-full overflow-y-auto scrollbar-hide">
      {/* Header */}
      <div className="flex items-center justify-between pt-4 mb-8">
        <h2 className="text-2xl font-black text-gray-900 tracking-tight">Financial Goals</h2>
        <button 
          onClick={() => setActiveScreen('create')}
          className="w-10 h-10 bg-[#00875A] text-white rounded-full flex items-center justify-center shadow-lg active:scale-95 transition-transform"
        >
          <Plus size={24} />
        </button>
      </div>

      {/* Total Savings */}
      <div className="bg-gray-50 rounded-[2rem] p-6 mb-8 flex items-center gap-4">
        <div className="w-12 h-12 bg-emerald-100 rounded-2xl flex items-center justify-center text-[#00875A]">
          <TrendingUp size={24} />
        </div>
        <div>
          <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest">Total Savings</p>
          <p className="text-2xl font-black text-gray-900">${totalSavings.toLocaleString()}</p>
        </div>
      </div>

      <h4 className="text-lg font-black text-gray-900 mb-4 px-1">Active Targets</h4>

      <div className="space-y-4">
        {goals.map((goal) => {
          const percentage = (goal.current / goal.target) * 100;
          return (
            <div 
              key={goal.id} 
              className="p-5 border border-gray-100 rounded-[2rem] hover:bg-gray-50 transition-colors cursor-pointer group"
              onClick={() => { setSelectedGoal(goal); setActiveScreen('details'); }}
            >
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h5 className="font-black text-gray-800 text-lg">{goal.title}</h5>
                  <p className="text-xs text-gray-400 font-bold">${goal.current.toLocaleString()} of ${goal.target.toLocaleString()}</p>
                </div>
                <div className="text-[#00875A] opacity-0 group-hover:opacity-100 transition-opacity">
                  <ChevronRight size={20} />
                </div>
              </div>

              {/* Progress Bar */}
              <div className="w-full h-3 bg-gray-100 rounded-full overflow-hidden">
                <div 
                  className={`h-full ${goal.color} rounded-full transition-all duration-1000`}
                  style={{ width: `${percentage}%` }}
                />
              </div>
              <p className="text-right mt-2 text-[10px] font-black text-gray-500 uppercase tracking-tighter">
                {Math.round(percentage)}% Completed
              </p>
            </div>
          );
        })}
      </div>
    </div>
  );
}
